/* Aula 15 — modelJs: Limpador de dados */

// A) limparTags
function limparTags(texto) {
  return [...new Set(
    texto
      .trim()
      .split(',')
      .map(t => t.trim().toLowerCase())
      .filter(t => t.length > 0)
  )];
}

// B) normalizarNome
function normalizarNome(texto) {
  return texto
    .trim()
    .toLowerCase()
    .split(' ')
    .filter(p => p.length > 0)
    .map(p => p[0].toUpperCase() + p.slice(1))
    .join(' ');
}

// C) somarNumerosValidos
function somarNumerosValidos(lista) {
  return lista
    .map(s => s.trim())
    .map(s => Number(s))
    .filter(n => Number.isFinite(n))
    .reduce((acc, n) => acc + n, 0);
}

console.log(limparTags('  css, JavaScript,  html , CSS  '));
console.log(normalizarNome('  bRUNo   cArValHo '));
console.log(somarNumerosValidos(['10', ' 20', '30 ', 'x']));
